import CartItem from './CartItem'
import { TProduct } from '../../Layout/app/Types'
import { Currency } from '../../Layout/app/Const'
import { Divider } from 'antd'
import React from 'react';
import { Flex, Input } from 'antd';

const { TextArea } = Input;

const CartBody = () => {
  const Product =   {
    id : 1,
    name:"Classic Rolex Watch",
    img : "../Product/Product.png",
    off : 15,
    rate:4.5,
    price:200,
    old_price:250,
    brand : "karim",
    description:"Wireless Bluetooth HeadsetFM Frequency Response: 87.5 108 MHz Feature: FM Radio, Card Supported (Micro SD / TF)Made in China",


  }
  const data :TProduct[] = [  Product,Product ] 

   return (
    <div className="CartBody">
            <div className="CartBody_Left">
            { data?.map((item,index)=>{
            return(
          <div key={index}>  <CartItem item={item}/> </div>
           ) })  }
           </div>
            <div className='CartBody_Right'>
              <div>
                <p>Total : </p> <h6>6000 {Currency}</h6>
              </div>
              <div className='Divider'>  <Divider /></div>
              <div>Additional Comments</div>
              <Flex vertical gap={32}>
    <Input showCount maxLength={20} onChange={onChange} />
    <TextArea showCount maxLength={100} onChange={onChange} placeholder="can resize" />
    <TextArea
      showCount
      maxLength={100}
      onChange={onChange}
      placeholder="disable resize"
      style={{ height: 120, resize: 'none' }}
    />
  </Flex>
              <div></div>
            </div>
    </div>
  )
}

export default CartBody
